var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"……오셨군요, 스승님.","JPN":"……いらっしゃったんですね、師匠。","ENG":"So you're finally here, Master.","TWN":"……師父來啦。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"미안하군. 서두른다고 했는데…… 아무래도 늦어버린 것 같아.","JPN":"すまない。急いだつもりだったが……どうやら間に合わなかったようだ。","ENG":"Sorry. I tried to hurry… but I fear it's too late.","TWN":"抱歉，說會趕到……結果還是晚了一步。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"괜찮습니다. 스승님 탓이 아니에요.","JPN":"大丈夫です、師匠のせいではありません。","ENG":"It's okay. It's not your fault.","TWN":"沒關係，不是師父的錯。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"조금은 더 견딜 줄 알았는데…… 광증의 진행이 갑자기 빨라졌어요.","JPN":"もう少し耐えられると思いましたが……狂症の進行が急に早まりました。","ENG":"I thought I could hold out a bit longer… but the madness is accelerating.","TWN":"我以為我還能再撐一下……但狂氣的作用突然加速。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"혹시…… 시윤이는 무사합니까?","JPN":"あの……シリュウは無事ですか？","ENG":"Is… Shiyoon all right?","TWN":"我們時雲……他沒事吧？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"쓰러지기 전에 뒷모습을 본 것 같은데……. 확실하지가 않아요.","JPN":"倒れる前に後ろ姿を見たような気がしますが……確信できなくて。","ENG":"I thought I saw his back before I fell… But I'm not so sure.","TWN":"我倒下前好像有看到他的背影……但又不太確定。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그 아이라면 창고에 잠시 눕혀 뒀다.","JPN":"……あの子なら倉庫に寝かせておいた。","ENG":"…The kid's lying in the warehouse.","TWN":"……我先把他安置在倉庫裡。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"피를 많이 흘리긴 했지만, 목숨은 건졌어.","JPN":"かなり出血していたようだが、一命をとりとめた。","ENG":"He lost a lot of blood, but he'll make it.","TWN":"雖然流了不少血，但撿回了一條小命。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그렇군요…… 다행입니다.","JPN":"そうだったんですね……よかったです。","ENG":"I see… Thank goodness.","TWN":"原來如此……那就好。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭔가…… 남길 말은 없나?","JPN":"なにか……言い残すことはないか？","ENG":"Any last words?","TWN":"你……有什麼要交代的嗎？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"연화는…… 그 고통을 견디면서도…… 최선을 다했습니다.","JPN":"レンカは……その苦痛に耐えながらも……最善を尽くしました。","ENG":"Yeonhwa tried her best… even as she withstood all that pain…","TWN":"蓮華她…已經盡力………忍受那個痛苦了。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"하지만 운명이란…… 번뇌란 참으로 끊어내기 어렵군요.","JPN":"しかし運命とは……煩悩というのは本当に断ち切れないものですね。","ENG":"But our fate… Kleshas seem to be impossibly insurmountable.","TWN":"只是……終究無法擺脫命運和煩惱。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그러니…… 마지막만큼은 고통 없이……","JPN":"だから……最期だけは苦しませずに……","ENG":"So please… When you put her down…","TWN":"我希望……她最後可以沒有痛苦地……"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그녀를…… 연화를 보내 주십시오……","JPN":"彼女を……レンカを眠らせてください……","ENG":"Please make it painless for Yeonhwa…","TWN":"離……開……"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……알겠다.","JPN":"……わかった。","ENG":"...Very well.","TWN":"……我知道了。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"약속해 주세요, 스승님. 그 아이를 보살펴 주겠다고.","JPN":"約束してください、師匠。あの子の面倒を見てくれると。","ENG":"Promise me, Master. Promise me that you'll take care of him.","TWN":"師父，答應我你會好好照顧他，"},"stage":{"bg":"MAINSTREAM_7110010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};